UIFriendBuildApplyItem = class("UIFriendBuildApplyItem", IGUIWindow)

function UIFriendBuildApplyItem:onLoad()
    print("UIFriendBuildApplyItem:onLoad()")
    self.icon = self:getChildWindow(0 , GUIType.UrlImage)
    self.icon:setDefaultImage("set:userItem.json image:icon")
    self.name = self:getChildWindow(1)
    self.sex = self:getChildWindow(2, GUIType.StaticImage)
    self.status = self:getChildWindow(3)
    self.text = self:getChildWindow(4)
    self.refuseBtn = self:getChildWindow(5):GetChildByIndex(0)
    self.refuseBtn:registerEvent(GUIEvent.ButtonClick, function()
        self:onRefuseButtonEvent()
    end)
    self.agreeBtn = self:getChildWindow(5):GetChildByIndex(1)
    self.agreeBtn:registerEvent(GUIEvent.ButtonClick, function()
        self:onAgreeButtonEvent()
    end)
    self.data = {}
end

function UIFriendBuildApplyItem:onRefuseButtonEvent()
    print("onRefuseButton")
    MultiBuildData:postRefuseInvite(GameData.userId, self.data.invitationId, self.data.userId)
    return
end

function UIFriendBuildApplyItem:onAgreeButtonEvent()
    local master = MultiBuildData:getBuildMaster()
    if master == nil then
        return
    end


    print("onAgreeButton")
    local tips = ""
    local smallTips = ""
    local oldMsterId = nil

    if #MultiBuildData.TogetherBuildData >=2 then
        if MultiBuildData:checkIsBuildMaster(userId) == false then
            tips = string.format(Lang:getString("you_have_join_island"), tostring(master.memberName))
            smallTips = string.format(Lang:getString("you_will_lost_a_build"), tostring(master.memberName))
        else
            tips = Lang:getString("you_build_group_is_max") 
        end
    else
        tips = string.format(Lang:getString("sure_join_other_build"), tostring(self.data.nickName)) 
