function UIFriendBuildApplyItem:getStatusText()
    if self.data.status == 0 then
        return Lang:getString("offline")
    end
    return Lang:getString("online")
end

function UIFriendBuildApplyItem:getSexIcon()
    if self.data.sex == 2 then
        return "set:skyblock_friend.json image:sex_girl"
    end
    return "set:skyblock_friend.json image:sex_boy"
end

function UIFriendBuildApplyItem:setItemData(data)
    print("UIFriendBuildApplyItem setItemData")
    self.data = data
    self:setDataUpdate()
end

function UIFriendBuildApplyItem:setDataUpdate()
    if self.data.pic then
        self.icon:setUrl(self.data.pic)
    end
    self.name:SetText(self.data.nickName)
    self.status:SetText(self:getStatusText())
    self.sex:SetImage(self:getSexIcon())
    self.text:SetText(Lang:getString("build_apply_text"))
end